function solve(grid) {
    const m = grid.length;
    const n = grid[0].length;

    // The total length of any path from (0, 0) to (m-1, n-1) is (m-1) + (n-1) + 1 = m + n - 1.
    // The maximum number of cells in the path is m + n - 1.
    // Since m*n <= 1000, the maximum path length is bounded, but we need to manage the state space.

    // The problem asks for the minimum XOR sum.
    // Since the path length is fixed (m+n-1), we can use Dynamic Programming or a search algorithm.
    // Because m*n <= 1000, the total number of states (i, j) is small.
    // However, the XOR value accumulated can vary widely.

    // Since the maximum value in grid[i][j] is 1023 (10 bits), the maximum possible XOR sum is less than 2048.

    // We can use DP where dp[i][j] stores the set of all possible XOR sums to reach (i, j).
    // Since m*n <= 1000, the path length is at most 1000. The number of distinct XOR sums is at most 2^10 = 1024.

    // Let's refine the DP state. dp[i][j] will be a Set of all possible XOR sums to reach (i, j).
    const dp = Array(m).fill(0).map(() => Array(n).fill(null).map(() => new Set()));

    // Initialization: Starting point (0, 0)
    dp[0][0].add(grid[0][0]);

    // Fill the first row
    for (let j = 1; j < n; j++) {
        const currentXOR = grid[0][j];
        for (const prevXOR of dp[0][j - 1]) {
            dp[0][j].add(prevXOR ^ currentXOR);
        }
    }

    // Fill the first column
    for (let i = 1; i < m; i++) {
        const currentXOR = grid[i][0];
        for (const prevXOR of dp[i - 1][0]) {
            dp[i][0].add(prevXOR ^ currentXOR);
        }
    }

    // Fill the rest of the grid
    for (let i = 1; i < m; i++) {
        for (let j = 1; j < n; j++) {
            const currentXOR = grid[i][j];

            // From top neighbor (i-1, j)
            for (const prevXOR of dp[i - 1][j]) {
                dp[i][j].add(prevXOR ^ currentXOR);
            }

            // From left neighbor (i, j-1)
            for (const prevXOR of dp[i][j - 1]) {
                dp[i][j].add(prevXOR ^ currentXOR);
            }
        }
    }

    // The result is the minimum value in the set at (m-1, n-1)
    const finalXORs = dp[m - 1][n - 1];
    if (finalXORs.size === 0) {
        // Should not happen based on constraints
        return -1;
    }

    let minXOR = Infinity;
    for (const xorValue of finalXORs) {
        if (xorValue < minXOR) {
            minXOR = xorValue;
        }
    }

    return minXOR;
}

